ee:variables.ee:set-variable:
%dw 2.0
var transactionType = attributes.queryParams.transactionType
var checkType = attributes.queryParams.checkType default "default"
var routingConfig = {
	salesOrder: {
		"default": {
			entity: "",
			queryParams: {

			}
		},
		catalogPrice: {
			entity: "inventory/v2/parts/prices",
			queryParams: {
				"companyId": attributes.queryParams.companyId ,
				"customerId": attributes.queryParams.customerId,
				"salesLocId": attributes.queryParams.salesLocId
			}
		}
	}
}
var selectedConfig = routingConfig[transactionType][checkType] default routingConfig[transactionType]."default"
output application/json
---
{
	method: "POST",
	host: Mule::p("p21.request.host"),
	port: Mule::p("p21.request.port"),
	basePath: "/api",
	path: "/" ++ (selectedConfig.entity default ""),
	headers: {
		Authorization: "Bearer " ++ (vars.accessToken default ""),

	},
	queryParams: selectedConfig.queryParams default {
	},
	uriParams: {
	},
	body: {
	}
}
